#include <stdio.h>
int main() {
    int N;
    scanf("%d", &N);
    int a[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &a[i]);
    }
    int dp[N][N];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            dp[i][j] = 0;
        }
    }
    for (int i = 0; i < N; i++) {
        dp[i][i] = 1;
    }
    for (int i = 1; i < N; i++) {
        for (int j = 0; j < i; j++) {
            if (a[i] % a[j] == 0) {
                for (int k = 0; k < N; k++) {
                    if (dp[j][k] > 0) {
                        dp[i][k] = (dp[i][k] > dp[j][k] + 1) ? dp[i][k] : dp[j][k] + 1;
                    }
                }
            }
        }
    }
    int max = 0;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            if (dp[i][j] > max) {
                max = dp[i][j];
            }
        }
    }
    printf("%d\n", max);
    return 0;
}

